const calculateTokens = (text: string): number => {
  // Simple estimation: 4 chars per token
  return Math.ceil(text.length / 4);
};

const inputData = $input.all()[0].json as any;
const fullContext = JSON.stringify({
  system: $node["AI Agent"].parameter["systemMessage"],
  history: inputData.chatHistory || [],
  user: inputData.userMessage
});

const tokenCount = calculateTokens(fullContext);
const MAX_TOKENS = 128000;

return {
  json: {
    tokenCount,
    overLimit: tokenCount > MAX_TOKENS,
    contextSize: fullContext.length,
    warning: tokenCount > MAX_TOKENS * 0.8
  }
};

const prevContextSize = $node["Previous AI Agent"].context?.["contextSize"] || 0;
const currentContext = $input.first().json;
const currentSize = JSON.stringify(currentContext).length;

const growthRate = ((currentSize - prevContextSize) / prevContextSize) * 100;

return {
  json: {
    currentSize,
    growthRate: growthRate.toFixed(2) + '%',
    exploding: growthRate > 50,
    recommendation: growthRate > 25 ? 'ADD_CONTEXT_TRIMMER' : 'OK'
  }
};

const memoryData = $input.first().json.memoryWindow || [];
const now = new Date();
const TWENTY_FOUR_HOURS = 24 * 60 * 60 * 1000;

let staleCount = 0;
const timestamps = memoryData.map((msg: any) => {
  const ts = new Date(msg.timestamp);
  if (now.getTime() - ts.getTime() > TWENTY_FOUR_HOURS) {
    staleCount++;
  }
  return ts;
});

return {
  json: {
    staleMessages: staleCount,
    totalMessages: memoryData.length,
    stalenessRatio: (staleCount / memoryData.length * 100).toFixed(1) + '%',
    needsPruning: staleCount > 3
  }
};

