const MAX_TOKENS = 100000;
const calculateTokens = (text: string) => Math.ceil(text.length / 4);

const inputData = $input.first().json;
let { chatHistory, userMessage, systemMessage } = inputData;

// Calculate current token usage
let currentTokens = calculateTokens(systemMessage || '') + calculateTokens(userMessage || '');
const historyCopy = [...(chatHistory || [])];

// Trim from oldest messages until under limit
while (currentTokens > MAX_TOKENS && historyCopy.length > 0) {
  const oldest = historyCopy.shift();
  currentTokens -= calculateTokens(JSON.stringify(oldest));
}

return {
  json: {
    chatHistory: historyCopy,
    userMessage,
    systemMessage,
    tokensSaved: (chatHistory?.length || 0) - historyCopy.length,
    finalTokenCount: currentTokens
  }
};

const summarizeToolOutput = (toolOutput: any): string => {
  if (typeof toolOutput === 'string') return toolOutput.slice(0, 2000) + '...';

  const keys = Object.keys(toolOutput);
  if (keys.length === 0) return 'Empty result';

  return keys.map(key => {
    const value = toolOutput[key];
    return `${key}: ${typeof value === 'object' ? JSON.stringify(value).slice(0, 500) : String(value).slice(0, 300)}`;
  }).join('\n');
};

const toolResults = $input.all().map(item => item.json);
const summarized = toolResults.map(result => ({
  ...result,
  summarizedOutput: summarizeToolOutput(result.output || result)
}));

return { json: summarized[0] };

const MAX_AGE_HOURS = 6;
const inputMemory = $input.first().json.memoryWindow || [];
const now = Date.now();

const pruneMemory = (messages: any[]) => 
  messages.filter(msg => 
    now - new Date(msg.timestamp).getTime() < MAX_AGE_HOURS * 60 * 60 * 1000
  );

const pruned = pruneMemory(inputMemory);

// Keep only most recent 50 messages if still too large
const finalMemory = pruned.slice(-50);

return {
  json: {
    memoryWindow: finalMemory,
    prunedCount: inputMemory.length - finalMemory.length,
    retentionHours: MAX_AGE_HOURS,
    currentSize: finalMemory.length
  }
};

