import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  webhookToken: $env.VEX_WEBHOOK_TOKEN,
  workflowId: $execution.id
});

// Monitor context window before AI Agent execution
await vex.track('ai_agent_context', {
  nodeName: $node.name,
  inputTokens: calculateTokens($input.first().json),
  chatHistoryLength: ($input.first().json.chatHistory || []).length,
  memoryWindowSize: $input.first().json.memoryWindow?.length || 0
});

// Auto-fix exploding contexts
if (vex.alerts.contextOverflow) {
  const trimmedInput = await vex.trimContext($input.first().json, {
    maxTokens: 100000,
    maxHistory: 20
  });
  return { json: trimmedInput };
}

// Forward to next node if healthy
return $input.all();
